from urllib.parse import urlparse, parse_qs, urlencode
import secrets
import hashlib
import time
from dataclasses import dataclass, field


@dataclass
class OAuthClient:
    client_id: str
    client_secret_hash: str
    # Register explicit redirect URIs for each environment
    registered_redirect_uris: list[str] = field(default_factory=list)
    client_name: str = ""


class OAuthAuthorizationServer:
    """
    OAuth 2.0 Authorization Server with secure redirect URI validation.

    Uses EXACT MATCH for redirect URIs. Register separate URIs for each
    environment (dev, staging, prod) rather than using unsafe substring matching.
    """

    def __init__(self):
        self.clients: dict[str, OAuthClient] = {}
        self.authorization_codes: dict[str, dict] = {}
        self.access_tokens: dict[str, dict] = {}
        self.code_expiry_seconds = 600
        self.token_expiry_seconds = 3600

    def register_client(
        self,
        client_name: str,
        redirect_uris: list[str],
    ) -> tuple[str, str]:
        """
        Register an OAuth client with explicit redirect URIs for each environment.

        Example:
            redirect_uris=[
                "https://myapp-dev.example.com/callback",
                "https://myapp-staging.example.com/callback",
                "https://myapp.example.com/callback",
                "http://localhost:8080/callback",  # local dev
            ]
        """
        for uri in redirect_uris:
            self._validate_uri_format(uri)

        client_id = secrets.token_urlsafe(32)
        client_secret = secrets.token_urlsafe(64)
        client_secret_hash = hashlib.sha256(client_secret.encode()).hexdigest()

        self.clients[client_id] = OAuthClient(
            client_id=client_id,
            client_secret_hash=client_secret_hash,
            registered_redirect_uris=redirect_uris,
            client_name=client_name,
        )

        return client_id, client_secret

    def _validate_uri_format(self, uri: str) -> None:
        """Validate that a URI is well-formed and uses a safe scheme."""
        parsed = urlparse(uri)
        if parsed.scheme not in ("https", "http"):
            raise ValueError(f"Redirect URI must use https (or http for localhost): {uri}")
        if parsed.scheme == "http" and parsed.hostname not in ("localhost", "127.0.0.1"):
            raise ValueError(f"HTTP scheme only allowed for localhost: {uri}")
        if not parsed.netloc:
            raise ValueError(f"Redirect URI must have a valid host: {uri}")
        if parsed.fragment:
            raise ValueError(f"Redirect URI must not contain a fragment: {uri}")

    def validate_redirect_uri(self, client_id: str, redirect_uri: str) -> bool:
        """
        Validate redirect_uri using EXACT MATCH against registered URIs.

        SECURITY NOTE: We intentionally use exact string matching, NOT substring
        or prefix matching. Prefix matching (startswith) is vulnerable to attacks
        like registering "https://example.com" and an attacker using
        "https://example.com.evil.com".
        """
        client = self.clients.get(client_id)
        if not client:
            return False

        # SECURE: Exact match only
        return redirect_uri in client.registered_redirect_uris

    def authorize(
        self,
        client_id: str,
        redirect_uri: str,
        response_type: str,
        scope: str,
        state: str,
        user_id: str,
    ) -> tuple[str, str | None]:
        """
        Process an authorization request. Returns (redirect_url, error).
        """
        client = self.clients.get(client_id)
        if not client:
            return "", "invalid_client"

        if not self.validate_redirect_uri(client_id, redirect_uri):
            # Do NOT redirect to an unvalidated URI — return error directly
            return "", "invalid_redirect_uri"

        if response_type != "code":
            error_url = self._build_error_redirect(
                redirect_uri, "unsupported_response_type", state
            )
            return error_url, "unsupported_response_type"

        # Generate authorization code
        code = secrets.token_urlsafe(48)
        self.authorization_codes[code] = {
            "client_id": client_id,
            "redirect_uri": redirect_uri,
            "user_id": user_id,
            "scope": scope,
            "expires_at": time.time() + self.code_expiry_seconds,
            "used": False,
        }

        params = urlencode({"code": code, "state": state})
        redirect_url = f"{redirect_uri}?{params}"
        return redirect_url, None

    def token_exchange(
        self,
        grant_type: str,
        code: str,
        redirect_uri: str,
        client_id: str,
        client_secret: str,
    ) -> tuple[dict | None, str | None]:
        """Exchange an authorization code for an access token."""
        if grant_type != "authorization_code":
            return None, "unsupported_grant_type"

        # Authenticate client
        client = self.clients.get(client_id)
        if not client:
            return None, "invalid_client"

        secret_hash = hashlib.sha256(client_secret.encode()).hexdigest()
        if not secrets.compare_digest(secret_hash, client.client_secret_hash):
            return None, "invalid_client"

        # Validate authorization code
        code_data = self.authorization_codes.get(code)
        if not code_data:
            return None, "invalid_grant"

        if code_data["used"]:
            # Code reuse detected — revoke all tokens for this code
            self.authorization_codes.pop(code, None)
            return None, "invalid_grant"

        if time.time() > code_data["expires_at"]:
            self.authorization_codes.pop(code, None)
            return None, "invalid_grant"

        if code_data["client_id"] != client_id:
            return None, "invalid_grant"

        # Redirect URI must match exactly what was used in the authorization request
        if code_data["redirect_uri"] != redirect_uri:
            return None, "invalid_grant"

        # Mark code as used
        code_data["used"] = True

        # Generate access token
        access_token = secrets.token_urlsafe(64)
        token_data = {
            "access_token": access_token,
            "token_type": "Bearer",
            "expires_in": self.token_expiry_seconds,
            "scope": code_data["scope"],
        }

        self.access_tokens[access_token] = {
            "client_id": client_id,
            "user_id": code_data["user_id"],
            "scope": code_data["scope"],
            "expires_at": time.time() + self.token_expiry_seconds,
        }

        return token_data, None

    def validate_access_token(self, token: str) -> dict | None:
        """Validate an access token and return its associated data."""
        token_data = self.access_tokens.get(token)
        if not token_data:
            return None
        if time.time() > token_data["expires_at"]:
            self.access_tokens.pop(token, None)
            return None
        return token_data

    def _build_error_redirect(
        self, redirect_uri: str, error: str, state: str
    ) -> str:
        params = urlencode({"error": error, "state": state})
        return f"{redirect_uri}?{params}"


